// In the AdminDashboard component, add this state at the top:
const [drivers, setDrivers] = useState([]);

// Update the fetchAllData function:
const fetchAllData = async () => {
  try {
    const [busesRes, bookingsRes, complaintsRes, driversRes] = await Promise.all([
      busAPI.getAllBuses(),
      bookingAPI.getAllBookings(),
      complaintAPI.getAllComplaints(),
      busAPI.getDriversList()
    ]);

    setBuses(busesRes.data);
    setBookings(bookingsRes.data);
    setComplaints(complaintsRes.data);
    setDrivers(driversRes.data);
  } catch (error) {
    toast.error('Failed to fetch data');
  }
};

// Update the busForm state:
const [busForm, setBusForm] = useState({
  busNumber: '',
  route: '',
  from: '',
  to: '',
  departureTime: '',
  totalSeats: 40,
  daysOfOperation: [],
  driver: '' // Add this
});

// Update the handleEditBus function:
const handleEditBus = (bus) => {
  setEditingBus(bus);
  setBusForm({
    busNumber: bus.busNumber,
    route: bus.route,
    from: bus.from,
    to: bus.to,
    departureTime: bus.departureTime,
    totalSeats: bus.totalSeats,
    daysOfOperation: bus.daysOfOperation || [],
    driver: bus.driver?._id || '' // Add this
  });
  setShowBusModal(true);
};

